from sympy import fibonacci
def A004780(n):
    def f(x):
        s = bin(x)[-1:1:-1]
        return n-1+sum(fibonacci(i+2) for i in range(len(s)) if s[i]=='1' and not '11' in s[i+1:])+('11' not in s)
    m, k = n, f(n)
    while m != k: m, k = k, f(k)
